1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	
15	const quoteResult = (premium: number) => ({ results: [{ premium }] });
16	
17	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
18	
19	const sum = (numbers: number[]): number =>
20	  numbers.reduce((total, n) => total + n, 0);
21	
22	const applyFirstInsuranceSurcharge = (amount: number): number =>
23	  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;
24	
25	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
26	
27	const isBlockOfThreeAlike = (items: Item[]): boolean =>
28	  items.length === 3 && items.every((item) => item.type === items[0].type);
29	
30	const groupByType = (items: Item[]): Item[][] => {
31	  const groups: Record<string, Item[]> = {};
32	  for (const item of items) {
33	    (groups[item.type] ||= []).push(item);
34	  }
35	  return Object.values(groups);
36	};
37	
38	const groupBasePremium = (group: Item[]): number =>
39	  isBlockOfThreeAlike(group)
40	    ? BLOCK_OF_THREE_BASE_PREMIUM
41	    : sum(group.map(itemBasePremium));
42	
43	const itemsBasePremium = (items: Item[]): number =>
44	  sum(groupByType(items).map(groupBasePremium));
45	
46	const quotePremiumFor = (items: Item[]): number =>
47	  Math.ceil(applyFirstInsuranceSurcharge(itemsBasePremium(items)) + PROCESSING_FEE);
48	
49	export const runScenario = (input: any): unknown => {
50	  const items: Item[] = input.steps[0].items;
51	  return quoteResult(quotePremiumFor(items));
52	};
