37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // === Components ===
45	  it("single rune → 25 base + 2.5 first (10%) + 5 fee = 32.5 → rounded up to 33 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 33 }] });
51	  });
52	  it("single moonstone → 25 base + 2.5 first (10%) + 5 fee = 33 G", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 33 }] });
58	  });
59	
60	  // === Building block of 3 alike components ===
61	  it("2 runes → 50 G base + 5 first (10%) + 5 fee = 60 G (no block)", () => {
62	    const result = runScenario({
63	      customer: { yearsWithMHPCO: 0 },
64	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
65	    });
66	    expect(result).toEqual({ results: [{ premium: 60 }] });
67	  });
68	  it("3 runes → 60 G base premium (block) + 6 first + 5 fee = 71 G", () => {
69	    const result = runScenario({
70	      customer: { yearsWithMHPCO: 0 },
71	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
72	    });
73	    expect(result).toEqual({ results: [{ premium: 71 }] });
74	  });
75	  it("4 runes → 100 G base + 10 first + 5 fee = 115 G (no block — block requires exactly 3)", () => {
76	    const result = runScenario({
77	      customer: { yearsWithMHPCO: 0 },
78	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
79	    });
80	    expect(result).toEqual({ results: [{ premium: 115 }] });
81	  });
82	  it("7 runes → 175 G base + 17.5 first + 5 fee = 197.5 → 198 G (no block; block requires exactly 3)", () => {
83	    const result = runScenario({
84	      customer: { yearsWithMHPCO: 0 },
85	      steps: [
86	        {
87	          op: "quote",
