102	    const result = runScenario({
103	      customer: { yearsWithMHPCO: 0 },
104	      steps: [
105	        {
106	          op: "quote",
107	          items: [
108	            { type: "rune" },
109	            { type: "rune" },
110	            { type: "rune" },
111	            { type: "moonstone" },
112	            { type: "moonstone" },
113	            { type: "moonstone" },
114	          ],
115	        },
116	      ],
117	    });
118	    expect(result).toEqual({ results: [{ premium: 137 }] });
119	  });
120	
121	  // === Item-specific modifiers ===
122	  it.todo("cursed sword adds 50% surcharge to the sword's base premium");
123	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (30%)");
124	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
125	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
126	
127	  // === Policy-wide modifiers ===
128	  it.todo("customer with exactly 2 years → loyalty discount (20%) applies");
129	  it.todo("customer with 1 year → no loyalty discount");
130	  it.todo("first ever insurance carries 10% initial assessment surcharge");
131	  it.todo("customer's second contract receives 15% follow-up discount");
132	
133	  // === Rounding ===
134	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
135	
136	  // === Integration examples ===
137	  it.todo("newcomer cursed sword (0 yrs, first contract, enchant 3) → premium 165 G");
138	  it.todo("long-standing customer's second cursed enchant-7 sword → premium 160 G");
139	
140	  // === Modifier scope on multi-item policies ===
141	  it.todo("cursed sword + plain amulet (0 yrs, first contract) → cursed surcharge on sword only");
142	
143	  // === Claim: basic reimbursement ===
144	  it.todo("regular sword (steel, enchant 3), damage 500 → payout 400 G (500 - 100 deductible)");
145	  it.todo("rune damage 200 → payout 100 G (200 - 100 deductible)");
146	
147	  // === Claim: enchantment threshold ===
148	  it.todo("steel sword enchant 9, damage 1000 → payout 400 G (50% then deductible)");
149	  it.todo("dragon-material sword enchant 9, damage 1000 → payout 400 G (50% wins, then deductible)");
150	  it.todo("dragon-material sword enchant 5, damage 800 → payout 700 G (full then deductible)");
151	  it.todo("dragon-material sword enchant exactly 8, damage 1000 → payout 400 G");
152	
153	  // === Claim: per-damage deductible ===
154	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
155	
156	  // === Multiple items of same type ===
157	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
158	  it.todo("policy with two swords, dragon attack damages both → each is treated as separate damage");
159	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
160	
161	  // === Cap ===
162	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
163	  it.todo("cursed sword: cap based on unmodified insurance value → cap 2000 G");
164	  it.todo("sword + 3 runes (block) → insurance sum 1750 G");
165	  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600");
166	  it.todo("sword cap 2000: second claim 1500 → payout 600 (limited by remaining cap), remainingCap 0");
167	
168	  // === Payout rounding ===
169	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
170	
171	  // === Edge cases / error handling ===
172	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
173	  it.todo("claim references damage for item not in policy → CLI exits non-zero, error on stderr");
174	  it.todo("claim damage entry with negative amount → CLI exits non-zero, error on stderr");
175	});
